import { shallowRef, triggerRef } from 'vue'

function createSignal(value, options) {
  const r = shallowRef(value)
  const get = () => r.value
  const set = (v) => {
    r.value = typeof v === 'function' ? v(r.value) : v
    if (options?.equals === false) triggerRef(r)
  }
  return [get, set]
}

const state = shallowRef({
  name: 'Who are you?'
})

state.value.name = "I'm Ray" // does NOT trigger update
state.value = { name: "I'm Ray" } // triggers update

// import shallowRef and triggerRef
import { shallowRef, triggerRef } from 'vue'

// createSignal takes a value and an options object
// options has an `equals` property
function createSignal(value, options) {
  // wrap value in shallowRef
  const r = shallowRef(value)
  // getter — only reads r.value when called
  const get = () => r.value
  // setter — accepts a value v
  const set = (v) => {
    // if v is a function, call it with the current value; otherwise just assign
    r.value = typeof v === 'function' ? v(r.value) : v
    // if options.equals is false, force trigger an update
    if (options?.equals === false) triggerRef(r)
  }

  // return [get, set]
  return [get, set]
}

const [ name, setName ] = createSignal({
  name: 'Who are you?'
})

const changeName = () => {
  setName((v) => {
    v.name = 'Mr. QQ'
  })
}

const [ name, setName ] = createSignal({
  name: 'Who are you?'
}, { equals: false })

const changeName = () => {
  setName((v) => {
    v.name = 'Mr. QQ'
  })
}
